class BookMyShow {
public:
    BookMyShow(int n, int m) {
        rows = n;
        seats = m;
    }

    vector<int> gather(int k, int maxRow) {
        int row = min(maxRow, rows - 1);
        int start = 0;
        while (start + k <= seats) {
            if (start + k <= seats && row <= maxRow) {
                return {row, start};
            }
            start++;
            row--;
            if (row < 0) return {};
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int row = 0;
        while (row <= maxRow && k > 0) {
            int seatsAvailable = seats - (row == 0 ? 0 : seats);
            if (seatsAvailable >= k) {
                k -= seats;
                row++;
            } else {
                int start = 0;
                while (start + k <= seats) {
                    if (start + k <= seats && row <= maxRow) {
                        return true;
                    }
                    start++;
                    row++;
                    if (row > maxRow) return false;
                }
                return false;
            }
        }
        return k == 0;
    }
private:
    int rows;
    int seats;
};
```

